var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 아쿠아리움, P. M. 19 : 37\\n<color=#ffd34c>조니 앤 멜로니</color> 대표 람다 스파타리, 비즈니스 미팅 중","JPN":"シャレードアクアリウム、P. M. 19 : 37\\n<color=#ffd34c>ジョニー＆メロニー</color>代表、ラムダ・スパタリー。ビジネスのミーティング中","ENG":"Charade Aquarium, 19:37\\nCEO of <color=#ffd34c>Jonie & Melonie</color>, Lamda Spatari, in a business meeting","TWN":"查雷德水族館，下午19:37\\n<color=#ffd34c>強尼&梅蘭妮</color>代表蘭達·史派特，商務會議中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"곧 마감 시간이라 그런지 한산하군요. 주말이랑은 전혀 다른 곳 같습니다.","JPN":"もうすぐ閉館の時間だからか、ずいぶんと静かですね。週末とはまったく別の場所のようです。","ENG":"It's quiet because it's nearly closing time. On weekends, it feels like a different place.","TWN":"不知道是不是因為快到關門時間了，好冷清啊。和週末簡直完全不一樣。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"직원들이 그러던데, 평소에도 동생 분과 자주 오신다면서요?","JPN":"職員から聞いたのですが、普段も妹さんとよく訪問されるそうですね。","ENG":"I heard from your staff that you come here often with your sister.","TWN":"聽職員們說，平時你也經常和妹妹一起來？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"어떻습니까? 이번 주말에 바람도 쐴 겸 저희 가족들이랑 같이 오시는 건.","JPN":"どうですか？　今週末に気分転換も兼ねて、私の家族と一緒に来るのは。","ENG":"So how about joining me and my family for some fresh air this weekend?","TWN":"怎麼樣？這週末跟我們家人一起來，也順便兜兜風。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"아내가 뱅쇼를 참 잘 만듭니다. 저도 겨울철에 자주 얻어 먹죠.","JPN":"妻の作るホットワインが逸品なんです。私も冬にはよく飲んでいますよ。","ENG":"My wife makes a mean vin chaud. I drink a lot of it in the winter.","TWN":"我太太很會做熱紅酒。冬天我也經常跟著她喝。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"불쾌하게 남의 사생활을 캐고 다니지 마십시오, 대리인.","JPN":"人のプライベートを探らないでください、代理人。不愉快です。","ENG":"Please do not pry into the private lives of others.","TWN":"不要打聽別人的私生活，讓人很反感，代理人。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그런 저급한 태도가 회사의 이미지를 깎아내릴 수 있다는 것도 모릅니까?","JPN":"そのような低級な態度が、会社のイメージを傷つける結果につながりかねないということがわからないのですか？","ENG":"Don't you realize that kind of crass attitude harms the company's image?","TWN":"你不知道這種諂媚的態度，可能會損害公司形象嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"하, 하하… 샤레이드의 기업들은 늘 유능한 로펌과 친분을 유지하고 싶어하니까요.","JPN":"は、はは……シャレードの企業は常に有能なローファームと親交を深めたいと思っていますからね。","ENG":"Ha, haha... The companies at Charade are always eager to maintain positive relations with a competent law firm.","TWN":"哈，哈哈……因為查雷德的企業，總是想和有能力的律師事務所保持友好關係。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"특히 조니 앤 멜로니와는 더욱 그렇죠.","JPN":"ジョニー＆メロニーとは特にそうです。","ENG":"Especially more, if that firm is Jonie & Melonie.","TWN":"和強尼&梅蘭妮更是如此。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"규정에 따르면 이 아쿠아리움은 13분 뒤 폐관하게 되어 있습니다.","JPN":"規定によると、このアクアリウムは13分後に閉館することになっています。","ENG":"According to the aquarium's operating hours, it will close in 13 minutes.","TWN":"根據規定，這家水族館將在13分鐘後關門。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"잡설은 그만하고 용건을 말하세요.","JPN":"無駄話はやめて、用件を話してください。","ENG":"So stop with your nonsense and get to the point.","TWN":"廢話少說，說正事吧。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"크흠, 어쩔 수 없군요.","JPN":"コホン、仕方ありませんね。","ENG":"Ahem. Understood.","TWN":"咳呃，好吧。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"대표님, 와일러라고 들어 보셨습니까?","JPN":"代表、ワイラーについて聞いたことはありますか？","ENG":"Ma'am, have you ever heard of a man named Wyler?","TWN":"代表，你聽說過瓦勒嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"뉴스 속보로는. 치정 문제 때문에 건틀렛에서 상대 직원을 살해했다죠.","JPN":"ニュースの速報でなら。痴情のもつれが原因で、ガントレットで相手の職員を殺したらしいですね。","ENG":"According to the news, he had killed another employee at the Gauntlet out of jealousy.","TWN":"在新聞速報上看到過。因為婚外情的問題，在聖鎧殺害了對方的職員。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"그렇습니다. 그 남자를 보석으로 풀려나게 도와 주십시오.","JPN":"そうです。その男が保釈を認められるように手伝っていただきたいのです。","ENG":"Yes. I was wondering if you could assist us in getting him released on bail.","TWN":"是的，請你幫忙把那個男人保釋出來。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"수임료는 준비되었습니까?","JPN":"ペイは準備できていますか？","ENG":"Have you got my commission fee ready?","TWN":"委託費準備好了嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"물론이죠. 장거리 통신과 관련된 특허 2건을 양도해 드리겠습니다.","JPN":"もちろんです。長距離通信に関する特許を2件、お譲りしましょう。","ENG":"Of course. I will hand you 2 patents pertaining to long-distance communication.","TWN":"當然。我們會轉讓2項和長途通訊有關的專利給你。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"귀사는 불한당들에게 꽤 후한 평가를 내리는군요.","JPN":"御社は悪党たちを相当高く評価していらっしゃるようですね。","ENG":"Your company seems to give rather generous assessments to outlaws.","TWN":"貴公司為了壞蛋們，可真是下了重本啊。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"알겠습니다. 내일 바로 접견하러 가죠.","JPN":"わかりました。明日すぐに接見に向かいましょう。","ENG":"Very well. I will go meet him first thing tomorrow.","TWN":"知道了。明天就去探視吧。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"매번 감사합니다, 대표님.","JPN":"いつもありがとうございます、代表。","ENG":"Thank you, ma'am.","TWN":"每次都很感謝你，代表。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PROMPT_NPC_NULL_NULL","text":{"KOREA":"차세대 스타로 키울 인재예요. 이번에도 잘 부탁드리겠습니다.","JPN":"次世代のスターとして育てようとしている人材ですので。今回もよろしくお願いいたします。","ENG":"We are planning to train him into the next big star. So we are counting on you.","TWN":"他是我們要當作新一代明星培養的人才。這次也麻煩你了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"흥, 차세대 스타? 잘 풀려 봤자 골빈 광고탑이겠지.","JPN":"ふん、次世代のスター？　うまく行っても空っぽ頭の広告塔でしょ。","ENG":"Hmph. Next big star? All he'll ever be is a mindless walking advertisement. And that is if you are even successful at all.","TWN":"哼，新一代明星？就算放出來了，應該也是個沒腦子的廣告機器吧。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님, 말씀은 다 나누셨습니까.","JPN":"学部長、お話はお済みですか？","ENG":"Dean, have you finished talking?","TWN":"學院院長，你都聊完了嗎。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L36_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그래. 언제나처럼 영양가 없는 대화였다.","JPN":"ああ。いつものようにメリットのない会話だった。","ENG":"Yes. As always, the conversation was fruitless.","TWN":"嗯，還是一如既往的無意義對話。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그런데 왜 내 허락도 없이 모습을 드러냈지? 학회와 관련된 일인가?","JPN":"ところで、どうして私の許可もなく姿を現した？　学会のことか？","ENG":"But why have you appeared before me without my consent? Do you have something to tell me regarding the Society?","TWN":"不過你為什麼沒經過我的允許就露面了？和學會的事有關？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"예. 생물학부장님의 연락입니다. 받으시죠.","JPN":"はい。生物学部長からの連絡です。どうぞ。","ENG":"Yes, it's a call from the Dean of Biology. Here you go.","TWN":"是的，生物學院院長來電話了，請你接一下。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"내가 먼저 그쪽에 연락하게 될 줄은 몰랐소. 정말 오래 살고 볼 일이야.","JPN":"私の方からそちらに連絡することになるとはな。長生きしてみるものだ。","ENG":"I never expected to be the one to call you first. What a sight to behold, eh?","TWN":"沒想到我會先聯絡你，還真是什麼事都有。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"주위가 소란스럽군요. 시설 점거 계획은 성공했습니까?","JPN":"周りが騒がしいですね。施設占拠の計画が成功したんですか？","ENG":"What's with all the ruckus over there? Have you succeeded in occupying the facility?","TWN":"周圍好吵。設施佔領計畫成功了？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그렇소. 그림자들 덕분에 예상보다 수월하게 풀렸다오.","JPN":"そうだ。シャドウのおかげで思っていたよりも容易だったのだ。","ENG":"Yes. It went smoothly thanks to the help from the Shadows.","TWN":"是的。多虧了暗影們幫忙，事情比預想得要順利。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"지금은 한창 사상자들을 수습하는 중이외다. 시간이 꽤 걸릴 듯하구려.","JPN":"今は死傷者の処置を行っている最中だ。それなりに時間がかかりそうだな。","ENG":"We are currently gathering casualties. However, I believe it will take some time.","TWN":"現在正在清理死傷者。似乎需要很長時間。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"의외로군요. 기관의 주력은 합중국으로 향했다고 들었습니다만.","JPN":"意外ですね。機関の主力は合衆国に向かったと聞きましたが。","ENG":"Strange. I heard that the Institution's main forces were headed to the States.","TWN":"我很意外。我聽說機關的主力都去合眾國了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"저항이 거세긴 했지만 프리드웬 때문만은 아니오.","JPN":"頑として抵抗していたが、プリドウェンのせいだけではあるまい。","ENG":"Resistance was strong, but that wasn't all because of Prydwen.","TWN":"抵抗很頑強，但不僅僅是因為普利多溫。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"굉장히 기이한…… 그래. 괴물 탓이지.","JPN":"とても奇妙な……そう。怪物のせいだった。","ENG":"It was also due to... Yes, an extremely strange monster getting involved.","TWN":"都因為一個看起來很……是的，很奇怪的怪物。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회장이 자리에 없었다면 피해가 걷잡을 수 없이 커졌을 거요.","JPN":"学会長がいなかったら、被害は手のつけようもないほど大きくなっていただろう。","ENG":"The consequences would have been far-reaching if the President had not been present.","TWN":"要不是學會長在，損失會慘重到無法控制。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"괴물? 침식체 말입니까?","JPN":"怪物？　侵食体のことですか？","ENG":"Monster? Do you mean a C.O.?","TWN":"怪物？是侵蝕體嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"글쎄… 침식체라기엔 침식파가 전혀 감지되지 않았소.","JPN":"どうだろうか……侵食体にしては侵食波がまったく感知されなかった。","ENG":"No idea... Given that we were unable to detect a Corruption ray, it might not be a CO.","TWN":"怎麼說呢……說是侵蝕體，卻又完全檢測不到侵蝕波。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회장이나 엘리시움의 지휘자는 뭔가 아는 눈치건만…. 말할 생각 없어 보이더군.","JPN":"学会長やエリシウムの指揮者は何か知ってそうだったが……話すつもりはないようだったな。","ENG":"The President and Elysium's Conductor seemed to know something about it, but... they had no interest in sharing that with us.","TWN":"學會長和愛樂組織的指揮家，好像知道是什麼……但是似乎並不打算說出來。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"지금부터 말하는 내용은 학회장의 전언이오.","JPN":"今から話す内容は学会長からの伝言だ。","ENG":"Also, a word from the President.","TWN":"現在我要說的話，是學會長讓我轉達的口信。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"현 시간부로 부학회장, 레지나 맥크레디의 권한이 한시적으로 정지되었소.","JPN":"現時刻をもって副学会長、レジーナ・マクレディーの権限が一時的に停止された。","ENG":"Vice President Regina MacCready's authorization has been temporarily revoked, effective immediately.","TWN":"從現在起，暫停副學會長蕾佳娜·麥克蕾蒂的許可權。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"권한 정지? 무슨 사유로?","JPN":"権限停止？　何の理由で？","ENG":"Revoked? On what grounds?","TWN":"暫停許可權？理由是什麼？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"학회장이 계획한 의식을 방해하고 도주했기 때문이오.","JPN":"学会長が計画した儀式を邪魔し、逃走したからだ。","ENG":"She interrupted the President's ritual and ran away.","TWN":"因為她妨礙學會長計畫的儀式，並逃走了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"마음 같아서는 내가 직접 뒤쫓고 싶소만……","JPN":"私が直接あとを追いたい気持ちは山々だが……","ENG":"I would've chased after her if I could, but...","TWN":"我倒是很想親自去追……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"중단된 의식을 다시 진행할 수 있도록 도와야 해서 말이오.","JPN":"中断された儀式を再び行うための手伝いをしないといけないのでな。","ENG":"I needed to help getting the ritual back on track.","TWN":"但我必須留下幫忙，讓中斷的儀式可以重新進行。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"부학회장을 잡아오시오. 배신자들을 다스리는 것도 법학부가 할 일 아니었던가?","JPN":"副学会長を捕まえて来てもらおう。裏切り者を処理するのも法学部の仕事であろう？","ENG":"Bring back the Vice President. Isn't it the Law Department's job to punish the traitors?","TWN":"請把副學會長抓回來。收拾叛徒，不也是法學院應該做的事嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"경솔한 발언이군요, 생물학부장.","JPN":"軽率な発言ですね、生物学部長。","ENG":"That's a rather imprudent remark, Dean of Biology.","TWN":"你的發言太草率了，生物學院院長。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"법학부의 소임은 학회 내부의 질서 확립이지 사냥개 노릇이 아닙니다.","JPN":"法学部は学会内部の秩序を確立することが任務であり、猟犬ではありません。","ENG":"The Law Department's role is to maintain order and discipline within the Society, not be its hound dog.","TWN":"法學院的職責是確立學會內部的秩序，不是獵犬。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"타 학부에 간섭하고 싶다면 더 신중하게 접근하도록 하십시오.","JPN":"他学部に口を出したければ、もう少し慎重に接近されたほうがよろしいかと。","ENG":"If you want to meddle in our affairs, you should take a more cautious approach.","TWN":"如果你想干涉其他學院，那請你更慎重一些。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"오, 이거 내가 젊은 학부장께 큰 실수를 했구려.","JPN":"おっと、これはこれは。若い学部長に大変な失礼を。","ENG":"Oh, I seem to have stepped on the toes of a young dean.","TWN":"噢，是我讓我們年輕的學院院長誤會了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"하긴 지금은 큰 그림을 못 보고 눈앞의 권력에 취해 있을 시기지.","JPN":"まあ、今は未来を見据えず、目の前の権力に酔いしれている時期だろう。","ENG":"But then again, now should be the time when you are drunk with power and unable to see the bigger picture.","TWN":"或許你對來說，現在正是看不到大局，沉醉於眼前權力的年紀。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"연장자로서 하나 충고해 주겠소. 주제 넘는 짓은 부디 때와 장소를 가려 하시오.","JPN":"年長者として一つ忠告しよう。調子に乗るのは時と場所をわきまえてからにしたまえ。","ENG":"As a senior, let me give you some advice. Be mindful of when you act out of line.","TWN":"作為年長者，我勸你一句。想做不自量力的事，一定要分清時間和場合。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"자기 능력만 믿고 설쳐도 무사할 만큼 현실은 그리 호락호락하지 않아.","JPN":"自分の能力だけを頼りに出しゃばって無事でいられるほど、現実はそう甘くないのだ。","ENG":"You won't get far in this world with just your abilities.","TWN":"過於相信自己的能力放肆撒野的話，現實可沒那麼溫柔。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"걱정 마시죠. 현실의 혹독함은 당신보다 잘 알고 있을 겁니다.","JPN":"ご心配いりません。現実の残酷さはあなたよりもよくわかっているつもりですので。","ENG":"Don't worry. I know how cruel the world is more than you do, I suppose.","TWN":"不用擔心，現實的殘酷我比你更清楚。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"하하, 밑바닥에서 기어올라 왔는데 어련하시려고.","JPN":"はは、どん底から這い上がってきたのだ。確かにそうかもしれんな。","ENG":"Haha. I'm sure you do. Seeing how you started from the bottom.","TWN":"哈哈，作為從底層一步步爬上來的人物，你確實更清楚呢。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"협력자들의 사진들이오. 하나는 평범한 영지민이고, 다른 하나는 외지인 용병이지.","JPN":"協力者の写真だ。一人は普通の領地民で、もう一人はよそ者の傭兵だ。","ENG":"These are the photo of the conspirators. One is a normal resident of the estate, and the other is a mercenary outlander.","TWN":"這些是幫手們的照片。一個是普通的領地居民，另一個是外地人傭兵。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"협력자……?","JPN":"協力者……？","ENG":"Conspirators...?","TWN":"幫手……？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그렇소. 용병 쪽은 어디로 튈지 모르는 계집이니 주의하시오.","JPN":"そうだ。傭兵の方は何をしでかすか予想のできない小娘だ。注意した方がいい。","ENG":"Yes. The mercenary girl is a loose cannon, so proceed with extreme caution around her.","TWN":"是的。傭兵是個不知道是從哪裡冒出來的丫頭，需要多加注意。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"예상 위치의 좌표를 보냈소이다. 그럼 수고하시오.","JPN":"予想位置の座標を送った。それでは頑張りたまえ。","ENG":"I've sent you the expected coordinates. Then, good luck.","TWN":"預計的位置座標已經發過去了。那就辛苦你了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"학부장님, 우선 양측의 입장을 확인한 뒤에 움직이는 게 어떻습니까.","JPN":"学部長、まずは双方の立場を確認してから行動されてはいかがでしょうか。","ENG":"Ma'am, why don't you make a move after you've confirmed both sides' positions?","TWN":"學院院長，先確認一下雙方的立場後，再行動怎麼樣？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ffd34c>학회장 대행을 등에 업고 우리를 견제하려는 속셈이다.</color>","JPN":"<color=#ffd34c>学会長代行を味方に、私たちを牽制するつもりだ。</color>","ENG":"<color=#ffd34c>He is trying to keep us in check with the Acting President behind him.</color>","TWN":"<color=#ffd34c>他是打算倚仗代理學會長牽制我們。</color>"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그렇게 말하고 싶은 건가?","JPN":"そう言いたいのか？","ENG":"Is this what you're trying to tell me?","TWN":"你是想這麼說嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"의식이 끝나면 비협조적이었던 학부들에게 피바람이 불지 않겠습니까?","JPN":"儀式が終わると、非協力的だった学部に血の嵐が吹き荒れるでしょう。","ENG":"I'm concerned that he will shed blood on uncooperative departments once the ritual is complete.","TWN":"儀式結束後，之前沒配合的學院，可能會被清算吧？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님이 쇠약해진 뒤로 과격한 지시의 빈도도 눈에 띄게 늘어났습니다.","JPN":"副学会長が衰弱した後、過激な指示の頻度も目に見えて増えました。","ENG":"Ever since the Vice President's condition worsened, the frequency of radical orders has noticeably increased.","TWN":"副學會長變得衰弱之後，她下達危險指示的頻率也明顯增加了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"어쩌면 부학회장님이 대행을 통제했기에……","JPN":"もしかすると副学会長が代行を統制していたから……","ENG":"Perhaps the Vice President's control over the Acting President...","TWN":"說不定是因為之前有副學會長約束代理……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"부학회장은 안나 부인과 다르단 말인가?","JPN":"副学会長はアンナ夫人とは違うと？","ENG":"So the Vice President is different from Madam Anna?","TWN":"你是想說副學會長和安娜夫人不一樣嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"나에게는 둘 다 마찬가지다. 사적인 변호라면 그만두도록.","JPN":"私にはどっちも同じだ。私的な弁護ならやめろ。","ENG":"Both are the same for me. You should stop defending her if it's a personal matter.","TWN":"對我來說，兩個人都一樣。如果是個人的辯護，就不用說了。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"죄, 죄송합니다. 그럴 뜻은 아니었습니다.","JPN":"も、申し訳ございません。そいういつもりではありませんでした。","ENG":"M-my apologies. I didn't mean it to sound like that.","TWN":"對…對不起，我不是那個意思。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"…못 미더운 녀석들뿐이군.","JPN":"……頼りないやつだらけだ。","ENG":"I'm surrounded by incompetents...","TWN":"……都是些靠不住的傢伙。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"생물학부장의 요구에 규정상 하자는 없다.","JPN":"生物学部長の要求に、規定上の問題はない。","ENG":"There is nothing wrong with Dean of Biology's request.","TWN":"生物學院院長的要求，從規定上來說沒有瑕疵。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"학회가 추진한 계획을 방해했다면, 부학회장에게도 응당 죄를 물어야겠지.","JPN":"学会が推し進めた計画を邪魔したのなら、副学会長にも当然罪を問うべきだろう。","ENG":"If the Vice President has interfered with the Society's plans, she must answer for her crimes.","TWN":"如果妨礙了學會推進的計畫，就該追究副學會長的責任。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"생물학부가 보낸 좌표는 고심도 이면세계를 가리키고 있습니다.","JPN":"生物学部から送られた座標は、高深度の裏世界を示しています。","ENG":"The coordinates he sent us are pointing to the hyperdepths of Counterside.","TWN":"生物學院發來的座標指向高深度異界。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"지금 바로 차원 함선을 수배할까요?","JPN":"今すぐ次元艦船を手配しましょうか？","ENG":"Shall I prepare a dimensional ship right now?","TWN":"現在馬上通緝次元艦船嗎？"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"아니. 뒤꽁무니나 쫓기보단 앞질러 가서 기다려야지.","JPN":"いや。後を追うより、先まわりして待とう。","ENG":"No. Rather than chasing after them, we should go ahead and cut them off.","TWN":"不，與其跟在屁股後面追，不如從前面包抄。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"부학회장이 어디에 있는지는 몰라도……","JPN":"副学会長がどこにいるかはわからないが……","ENG":"We might not know where the Vice President is right now...","TWN":"雖然不知道副學會長在哪裡……"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"어디로 갈지는, 짚이는 곳이 있다.","JPN":"どこへ向かうかは、心当たりがある。","ENG":"I do have a hunch as to where she will go.","TWN":"但關於她要去的地方，我有個猜想。"},"stage":{"bg":"AQUARIUM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};